begin;
create extension if not exists pgtap;
insert into auth.users (id, aud, role, email, encrypted_password, email_confirmed_at) values ('00000000-0000-0000-0000-000000000101', 'authenticated', 'authenticated', 'report-owner@example.test', 'local-test-only', timezone('utc', now())) on conflict (id) do nothing;
insert into public.organizations (id, name, display_name, slug) values ('d1000000-0000-0000-0000-000000000001', 'Report Organization', 'Report Organization', 'report-organization'), ('d1000000-0000-0000-0000-000000000002', 'Other Report Organization', 'Other Report Organization', 'other-report-organization');
insert into public.organization_memberships (id, organization_id, profile_id, status, accepted_at) values ('d2000000-0000-0000-0000-000000000001', 'd1000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000101', 'active', timezone('utc', now()));
insert into public.membership_roles (organization_id, membership_id, role_id) select 'd1000000-0000-0000-0000-000000000001', 'd2000000-0000-0000-0000-000000000001', id from public.roles where key = 'organization.owner';
select plan(10);
set local role anon;
select throws_ok($$select public.get_dashboard_summary('d1000000-0000-0000-0000-000000000001')$$, 'P0001', 'Permission denied', 'anonymous dashboard access is denied');
set local role authenticated;
select set_config('request.jwt.claim.sub', '00000000-0000-0000-0000-000000000101', true);
create temp table report_patient on commit drop as select * from public.create_patient('d1000000-0000-0000-0000-000000000001', 'RP-001', 'Report', null, 'Patient', null, null, '1980-01-01', 'undisclosed', null, null, 'undisclosed', null, 'en', false, null, null, null, 'active', null, null);
select is((select active_patients from public.vw_dashboard_summary where organization_id = 'd1000000-0000-0000-0000-000000000001'), 1, 'dashboard view counts tenant patients');
select is((select count(*)::integer from public.vw_dashboard_summary where organization_id = 'd1000000-0000-0000-0000-000000000002'), 0, 'dashboard view excludes another tenant');
select is(((public.get_dashboard_summary('d1000000-0000-0000-0000-000000000001')->>'patients')::integer), 1, 'dashboard RPC returns filtered patient count');
select is(jsonb_array_length(public.get_patient_growth('d1000000-0000-0000-0000-000000000001')), 1, 'patient growth RPC returns a monthly aggregate');
select throws_ok($$select public.get_dashboard_summary('d1000000-0000-0000-0000-000000000002')$$, 'P0001', 'Permission denied', 'cross-tenant dashboard RPC is denied');
select throws_ok($$insert into public.report_saved_filters(organization_id, report_key, name) values ('d1000000-0000-0000-0000-000000000001', 'dashboard', 'Denied')$$, '42501', null, 'direct saved-filter writes are denied');
select lives_ok($$select public.request_report_export('d1000000-0000-0000-0000-000000000001', 'dashboard', 'csv', '{}'::jsonb)$$, 'export placeholder is permission checked');
select lives_ok($$select public.save_report_filter('d1000000-0000-0000-0000-000000000001', null, 'dashboard', 'Default', '{"period":"month"}'::jsonb)$$, 'saved filter is permission checked');
set local role postgres;
select ok((select count(*) from public.audit_events where organization_id = 'd1000000-0000-0000-0000-000000000001' and action in ('report.dashboard_accessed', 'report.export_requested', 'report.saved_filter_updated')) >= 3, 'report access and export mutations are audited');
select * from finish();
rollback;
